import{_ as a,o,c as t,a0 as i}from"./chunks/framework.7S7UUFQz.js";const h=JSON.parse('{"title":"Dataset Compatibility","description":"","frontmatter":{},"headers":[],"relativePath":"dataset-compatibility.md","filePath":"dataset-compatibility.md"}'),r={name:"dataset-compatibility.md"};function d(s,e,c,l,n,p){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="dataset-compatibility" tabindex="-1">Dataset Compatibility <a class="header-anchor" href="#dataset-compatibility" aria-label="Permalink to &quot;Dataset Compatibility&quot;">​</a></h1><p>TerritoryKit datasets are versioned separately from package releases. The runtime reads <code>manifest.datasetVersion</code>, <code>manifest.schemaVersion</code>, <code>manifest.sourceDate</code>, and <code>manifest.geometryHash</code> before loading zones.</p><h2 id="policy" tabindex="-1">Policy <a class="header-anchor" href="#policy" aria-label="Permalink to &quot;Policy&quot;">​</a></h2><ul><li><code>schemaVersion</code> describes the JSON shape. The initial value is <code>territory-schema@1</code>.</li><li><code>datasetVersion</code> follows SemVer for the published dataset artifact.</li><li><code>sourceDate</code> records the authority/source snapshot date, not the package publish date.</li><li><code>geometryHash</code> must change when any zone geometry changes.</li><li><code>compatibility.minCoreVersion</code> can be used when a dataset requires a newer engine behavior.</li></ul><h2 id="real-world-imports" tabindex="-1">Real-World Imports <a class="header-anchor" href="#real-world-imports" aria-label="Permalink to &quot;Real-World Imports&quot;">​</a></h2><p>Administrative GeoJSON must use RFC 7946 coordinate order: <code>[longitude, latitude]</code>. <code>Polygon</code> and <code>MultiPolygon</code> are accepted; <code>Point</code>, <code>LineString</code>, and <code>GeometryCollection</code> are rejected for territory zones. Holes and island MultiPolygons are valid, but source data must be normalized to EPSG:4326 before import.</p><p>Validation issues expose <code>featureId</code>, <code>sourcePath</code>, and <code>repairSuggestion</code> where possible so CLI and import pipelines can point back to the dirty source feature.</p><p>Load-time validation rejects stale <code>bbox</code> and <code>center</code> metadata when they no longer match the geometry. Non-reciprocal <code>neighborIds</code> are warnings so legacy datasets can still load while import pipelines repair adjacency lists.</p>',8)])])}const u=a(r,[["render",d]]);export{h as __pageData,u as default};
